### 5. Daemon --foreground Mode Changes
```rust
// src/daemon/main.rs
pub fn run_daemon(opts: DaemonOpts) -> Result<()> {
    let config = load_daemon_config()?;

    if opts.foreground {
        // Run in foreground (for service managers)
        tracing::info!("Starting xf-daemon in foreground mode");

        if opts.systemd {
            // Notify systemd we are ready
            sd_notify::notify(true, &[sd_notify::NotifyState::Ready])?;

            // Set up watchdog timer
            if let Some(usec) = sd_notify::watchdog_enabled(false) {
                let interval = Duration::from_micros(usec / 2);
                tokio::spawn(async move {
                    loop {
                        sd_notify::notify(false, &[sd_notify::NotifyState::Watchdog]).ok();
                        tokio::time::sleep(interval).await;
                    }
                });
            }
        }

        run_server(config).await?;
    } else {
        // Daemonize (double-fork)
        daemonize(config)?;
    }

    Ok(())
}
```

### 6. Health Check Command
```rust
// src/daemon/health.rs
pub async fn health_check(socket_path: &Path) -> Result<HealthStatus> {
    let client = DaemonClient::new_with_path(socket_path);
    let timeout = Duration::from_secs(5);

    match tokio::time::timeout(timeout, client.health()).await {
        Ok(Ok(status)) => {
            tracing::info!(
                uptime_secs = status.uptime_secs,
                models_loaded = status.models_loaded,
                memory_mb = status.rss_mb,
                "Daemon healthy"
            );
            Ok(status)
        }
        Ok(Err(e)) => {
            tracing::error!(error = %e, "Daemon unhealthy");
            Err(e)
        }
        Err(_) => {
            tracing::error!("Daemon health check timed out");
            Err(anyhow::anyhow!("Health check timed out after {}s", timeout.as_secs()))
        }
    }
}
```

