### 2. Embedding Quality Tests (Per-Model)
```rust
/// Test that each model can distinguish related from unrelated texts
fn quality_test_for_model(model: &dyn Embedder) {
    let pairs = vec![
        ("buy bitcoin cryptocurrency", "crypto trading exchange", true),
        ("buy bitcoin cryptocurrency", "chocolate cake recipe baking", false),
        ("machine learning neural networks", "deep learning training data", true),
        ("machine learning neural networks", "flower arrangement centerpiece", false),
        ("rust programming language safety", "systems programming memory safe", true),
        ("rust programming language safety", "vacation resort beach hotel", false),
    ];

    for (query, doc, should_be_related) in pairs {
        let q = model.embed(query).unwrap();
        let d = model.embed(doc).unwrap();
        let sim = cosine_similarity(&q, &d);

        tracing::info!(
            model = model.model_name(),
            query = query,
            doc = doc,
            similarity = sim,
            expected_related = should_be_related,
            "Quality check"
        );

        if should_be_related {
            assert!(sim > 0.3, "{} x {}: expected related (>0.3), got sim={}", query, doc, sim);
        } else {
            assert!(sim < 0.7, "{} x {}: expected unrelated (<0.7), got sim={}", query, doc, sim);
        }
    }
}

#[test]
fn test_minilm_quality() { quality_test_for_model(&minilm_embedder()); }
#[test]
fn test_bge_small_quality() { quality_test_for_model(&bge_small_embedder()); }
#[test]
fn test_embedding_gemma_quality() { quality_test_for_model(&gemma_embedder()); }
