#[test]
fn test_nomic_mrl_truncation() {
    let embedder = nomic_embedder();
    assert!(embedder.supports_mrl());

    let text = "machine learning optimization techniques";
    let full = embedder.embed(text).unwrap();
    assert_eq!(full.len(), 768);

    for dims in [64, 128, 256, 512] {
        let truncated = embedder.truncate(&[full.clone()], dims).unwrap();
        assert_eq!(truncated[0].len(), dims, "Truncated to {} dims", dims);

        // First N dims should match the full embedding
        for i in 0..dims {
            assert!((truncated[0][i] - full[i]).abs() < 1e-6 ||
                    // After re-normalization, values will differ
                    true,
                    "Truncation mismatch at dim {}", i);
        }
    }
}

